  ('ef9d65f3-726a-488a-af86-4074b784d357', 'SET DIFFERENCE operation (R - S) returns:', 'Tuples in R but not in S', 'Tuples in S but not in R', 'Tuples in both', 'All tuples', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which operation is not commutative?', 'SET DIFFERENCE', 'UNION', 'INTERSECTION', 'Both A and B', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If R and S are union compatible, R ∪ S = S ∪ R demonstrates:', 'Commutativity of UNION', 'Associativity of UNION', 'Distributivity', 'Idempotence', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'R ∪ (S ∪ T) = (R ∪ S) ∪ T demonstrates:', 'Associativity', 'Commutativity', 'Distributivity', 'Idempotence', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'R ∩ R = R demonstrates:', 'Idempotence', 'Commutativity', 'Associativity', 'Distributivity', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The identity element for UNION is:', 'Empty relation', 'Universal relation', 'R itself', 'None', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which of the following is true?', 'All of the above', 'R ∩ (S ∪ T) = (R ∩ S) ∪ (R ∩ T)', 'R ∩ (S ∪ T) = (R ∪ S) ∩ (R ∪ T)', 'R ∪ (S ∩ T) = (R ∪ S) ∩ (R ∪ T)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The cardinality of R ∪ S is at most:', '|R| + |S|', '|R| × |S|', '|R| - |S|', 'min(|R|, |S|)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The cardinality of R ∩ S is at most:', 'min(|R|, |S|)', 'max(|R|, |S|)', '|R| + |S|', '|R| × |S|', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If R and S are disjoint, then |R ∪ S| =:', '|R| + |S|', '|R| - |S|', 'min(|R|, |S|)', 'max(|R|, |S|)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which operation can be expressed using other operations?', 'INTERSECTION', 'UNION', 'SET DIFFERENCE', 'CARTESIAN PRODUCT', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'CARTESIAN PRODUCT (R × S) combines:', 'Both tuples and attributes', 'Tuples from R with tuples from S', 'Attributes from R with attributes from S', 'Only matching tuples', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If R has m tuples and n attributes, S has p tuples and q attributes, then R × S has:', 'm × p tuples, n + q attributes', 'm + p tuples, n + q attributes', 'm × p tuples, n × q attributes', 'm + p tuples, n × q attributes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'CARTESIAN PRODUCT without any selection usually produces:', 'Meaningless results', 'Useful combined data', 'Empty relation', 'Index', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'R × S = S × R demonstrates:', 'Commutativity', 'Associativity', 'Distributivity', 'Idempotence', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', '(R × S) × T = R × (S × T) demonstrates:', 'Associativity', 'Commutativity', 'Distributivity', 'Idempotence', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The JOIN operation is derived from:', 'CARTESIAN PRODUCT followed by SELECT', 'UNION followed by PROJECT', 'INTERSECTION followed by RENAME', 'DIFFERENCE followed by UNION', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'THETA JOIN (R ⋈θ S) uses:', 'Any comparison condition θ', 'Only equality condition', 'Only less than condition', 'No condition', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'EQUIJOIN is a THETA JOIN with:', 'Equality condition only', 'Any condition', 'Greater than condition', 'Less than condition', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'NATURAL JOIN (R ⋈ S) eliminates:', 'Duplicate attributes (common columns)', 'Duplicate tuples', 'Null values', 'Foreign keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Natural join automatically joins on:', 'Attributes with same name in both relations', 'Primary keys', 'Foreign keys', 'First attribute', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If R and S have no common attributes, then R ⋈ S =:', 'R × S', 'R ∪ S', 'R ∩ S', 'R - S', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'OUTER JOIN preserves:', 'Non-matching tuples from one or both relations', 'Only matching tuples', 'No tuples', 'Only null values', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'LEFT OUTER JOIN (R ⟕ S) preserves:', 'All tuples from left relation (R)', 'All tuples from right relation (S)', 'All tuples from both', 'Only matching tuples', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'RIGHT OUTER JOIN (R ⟖ S) preserves:', 'All tuples from right relation', 'All tuples from left relation', 'All tuples from both', 'Only matching tuples', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'FULL OUTER JOIN (R ⟗ S) preserves:', 'All tuples from both relations', 'All tuples from left relation only', 'All tuples from right relation only', 'Only matching tuples', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'In LEFT OUTER JOIN, non-matching tuples from left relation have:', 'NULL values for right relation attributes', 'Zero values', 'Empty strings', 'Deleted', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'SEMI JOIN (R ⋉ S) returns:', 'Tuples in R that match with some tuple in S', 'All tuples from both', 'Only matching attributes', 'Cartesian product', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'ANTI JOIN returns:', 'Tuples in R with no match in S', 'Tuples in both', 'All tuples', 'Cartesian product', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The number of tuples in natural join is at most:', '|R| × |S|', '|R| + |S|', 'min(|R|, |S|)', 'max(|R|, |S|)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which join is most commonly used in practice?', 'Equijoin', 'Natural join', 'Outer join', 'Theta join', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The DIVISION operation (R ÷ S) is used for queries involving:', '"All" conditions', '"Any" conditions', '"Exists" conditions', '"Not" conditions', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'For R ÷ S to be valid:', 'Attributes of S must be subset of attributes of R', 'R and S must have same attributes', 'S must have more attributes than R', 'No condition', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If R has attributes (A, B) and S has attribute (B), then R ÷ S returns:', 'A values that are associated with every B in S', 'All A values', 'All B values', 'Cartesian product', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The division operation can be expressed as:', 'R ÷ S = πA(R) - πA((πA(R) × S) - R)', 'R ÷ S = R × S', 'R ÷ S = R - S', 'R ÷ S = R ∪ S', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If S is empty, then R ÷ S =:', 'π attributes of R that are not in S (R)', 'Empty relation', 'R itself', 'Error', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Aggregate operations in relational algebra include:', 'SUM, COUNT, AVG, MAX, MIN', 'SELECT, PROJECT', 'JOIN, UNION', 'DIVIDE, RENAME', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'GROUP BY in relational algebra is represented using:', 'Aggregation with grouping attributes', 'Simple SELECT', 'PROJECT only', 'JOIN only', NULL, true),
