  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Find names of employees working in department ''IT'' (Relational Algebra):', 'π name (σ dept=''IT'' (Employee))', 'σ dept=''IT'' (π name (Employee))', 'π name ⋈ σ dept=''IT'' (Employee)', 'ρ name (σ dept=''IT'' (Employee))', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Find names of employees working in ''IT'' or earning >50000:', 'π name (σ dept=''IT'' ∨ salary>50000 (Employee))', 'π name (σ dept=''IT'' ∧ salary>50000 (Employee))', 'σ dept=''IT'' (π name (Employee)) ∪ σ salary>50000 (π name (Employee))', 'Both A and similar expressions', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Find names of employees who work on project ''P1'' (Employee ⋈ Works_on):', 'All of the above are equivalent', 'π name (Employee ⋈ (σ project=''P1'' (Works_on)))', 'σ project=''P1'' (Employee × Works_on)', 'π name (σ project=''P1'' (Employee × Works_on))', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Find suppliers who supply all parts (Division query):', 'π supplier (Supplies ÷ π part (Parts))', 'π supplier (Supplies) × Parts', 'σ supplier (Supplies ÷ Parts)', 'π supplier (Supplies ⋈ Parts)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'In tuple relational calculus, find names of employees earning >50000:', 'All of the above with appropriate syntax', '{ t.name | Employee(t) ∧ t.salary > 50000 }', '{ t | Employee(t) ∧ t.salary > 50000 }', '{ name | ∃ e (Employee(e) ∧ e.salary > 50000 ∧ name = e.name) }', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'w.proj_id = p.id)) }', '{ e.name | Employee(e) ∧ ∃ p (Project(p) ∧ Works_on(w)) }', '{ e.name | ∀ p (Project(p) ∧ Works_on(w)) }', '{ e.name | Works_on(e) }', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The query { t | Employee(t) ∧ ∃ d (Department(d) ∧ d.dept_name = ''IT'' ∧ t.dept_id =', 'Employees in IT department', 'All employees', 'IT department details', 'Department names', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which of the following is NOT a property of relational algebra?', 'Record-at-a-time processing', 'Closure property', 'Procedural nature', 'Set-at-a-time processing', NULL, true),
