  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Armstrong''s axioms include:', 'Reflexivity, Augmentation, Transitivity', 'Reflexivity, Symmetry, Transitivity', 'Reflexivity, Augmentation, Union', 'Decomposition, Union, Pseudo-transitivity', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Reflexivity rule states:', 'If Y ⊆ X, then X → Y', 'If X → Y, then X → Y', 'If X → Y and Y → Z, then X → Z', 'If X → Y, then XZ → YZ', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Augmentation rule states:', 'If X → Y, then XZ → YZ', 'If X → Y, then X → YZ', 'If X → Y and Y → Z, then X → Z', 'If X → Y and X → Z, then X → YZ', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Transitivity rule states:', 'If X → Y and Y → Z, then X → Z', 'If X → Y, then XZ → YZ', 'If X → Y and X → Z, then X → YZ', 'If X → Y, then X → Y', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Additional inference rules derived from Armstrong''s axioms include:', 'Union, Decomposition, Pseudo-transitivity', 'Union, Intersection, Difference', 'Join, Product, Division', 'Select, Project, Rename', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Union rule states:', 'If X → Y and X → Z, then X → YZ', 'If X → YZ, then X → Y and X → Z', 'If X → Y and YZ → W, then XZ → W', 'If X → Y, then XZ → Y', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Decomposition rule states:', 'If X → YZ, then X → Y and X → Z', 'If X → Y and X → Z, then X → YZ', 'If X → Y and YZ → W, then XZ → W', 'If X → Y, then XZ → Y', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Pseudo-transitivity rule states:', 'If X → Y and YZ → W, then XZ → W', 'If X → Y and Y → Z, then X → Z', 'If X → YZ, then X → Y and X → Z', 'If X → Y and X → Z, then X → YZ', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The closure of a set of attributes X+ is:', 'Set of all attributes functionally determined by X', 'Set of all keys', 'Set of all FDs', 'Set of all relations', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'To find if X → Y holds, we can:', 'Compute X+ and check if Y ⊆ X+', 'Check all tuples manually', 'Use trial and error', 'Assume it holds', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The closure of a set of FDs F+ is:', 'All FDs that can be derived from F', 'All attributes in the relation', 'All keys', 'All superkeys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A candidate key can be found by computing:', 'Attribute closure that includes all attributes', 'Any attribute', 'First attribute only', 'Last attribute only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A superkey is:', 'A set of attributes that determines all attributes', 'A primary key', 'A foreign key', 'Any attribute', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A candidate key is:', 'Minimal superkey', 'Any superkey', 'Primary key', 'Foreign key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Given R(A,B,C) with FDs: A → B, B → C. Candidate key(s) is/are:', 'A', 'B', 'C', 'AB', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Given R(A,B,C) with FDs: AB → C, C → A. Candidate key(s) is/are:', 'AB and BC', 'A only', 'B only', 'C only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The closure of FDs can be computed using:', 'Armstrong''s axioms repeatedly', 'Trial and error', 'Random selection', 'Table scan', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'An FD X → Y is redundant if:', 'It can be derived from other FDs', 'It is trivial', 'It is non-trivial', 'It involves all attributes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A minimal cover of FDs is:', 'Smallest set of FDs equivalent to original', 'Largest set of FDs', 'Set of all FDs', 'Set of candidate keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Minimal cover must satisfy:', 'Right side single attribute, no redundant FDs, no extraneous attributes', 'Left side single attribute', 'All FDs trivial', 'All FDs non-trivial', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation is in 1NF if:', 'All attributes are atomic (no repeating groups)', 'It has a primary key', 'No transitive dependencies', 'No partial dependencies', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which violates 1NF?', 'Attribute containing multiple phone numbers in one cell', 'Attribute with NULL value', 'Attribute with integer value', 'Attribute with date value', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Repeating groups in a relation indicate:', 'Violation of 1NF', 'Compliance with 1NF', 'Good design', 'Normalized design', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'To convert to 1NF, we can:', 'Create separate table for repeating group or flatten', 'Add more columns', 'Remove all NULLs', 'Add primary key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Example of non-atomic attribute:', 'Address that contains street, city, state, zip', 'Salary amount', 'Employee ID', 'Hire date', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', '1NF allows:', 'Only atomic values per cell', 'Multi-valued attributes', 'Composite attributes', 'Nested relations', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A table with columns (EmpID, Phone1, Phone2, Phone3) is in 1NF but has:', 'Design problem (limited number of phones)', 'Good design', 'No issues', 'Atomic values problem', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation is in 2NF if:', 'It is in 1NF and no partial dependencies', 'It is in 1NF only', 'No transitive dependencies', 'All determinants are candidate keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Partial dependency means:', 'Non-key attribute depends on part of composite key', 'Attribute depends on whole key', 'Attribute depends on another non-key', 'Key depends on non-key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which is a partial dependency?', 'StudentID → StudentName', 'StudentID, CourseID → Grade', 'CourseID → Grade', 'StudentID, CourseID → StudentName', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', '2NF violation occurs only in relations with:', 'Composite primary keys', 'Single attribute keys', 'No keys', 'Foreign keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'To convert to 2NF, we:', 'Remove partial dependencies by decomposing', 'Add more attributes', 'Remove all dependencies', 'Add surrogate key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Given R(A,B,C,D) with key (A,B) and FDs: A → C, B → D. This relation is in:', '1NF but not 2NF', '2NF', '3NF', 'BCNF', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'After decomposing the above into 2NF, we get:', 'R1(A,C), R2(B,D), R3(A,B)', 'R1(A,B,C), R2(B,D)', 'R1(A,C), R2(A,B,D)', 'R1(A,B), R2(C,D)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation is in 3NF if:', 'It is in 2NF and no transitive dependencies', 'It is in 2NF only', 'No partial dependencies', 'All determinants are candidate keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Transitive dependency means:', 'Non-key attribute depends on another non-key attribute', 'Attribute depends on key', 'Key depends on non-key', 'Attribute depends on part of key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'has:', 'Transitive dependency EmpID → DeptName', 'Partial dependency', 'No dependency', 'Direct dependency only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'This relation is in:', '2NF but not 3NF', '3NF', 'BCNF', '1NF only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'To convert to 3NF, we decompose into:', 'R1(EmpID, DeptID), R2(DeptID, DeptName)', 'R1(EmpID, DeptName), R2(DeptID, DeptName)', 'R1(EmpID, DeptID, DeptName)', 'R1(EmpID), R2(DeptID, DeptName)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', '3NF allows:', 'A non-key to determine another non-key if the determinant is a candidate key', 'No dependencies at all', 'Only key dependencies', 'Partial dependencies', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The 3NF definition: For every FD X → A, either:', 'X is a superkey or A is part of some candidate key', 'X is a key only', 'A is non-key', 'X is non-key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation in 3NF but not BCNF has:', 'Overlapping candidate keys with dependencies', 'No candidate keys', 'Single attribute key', 'No FDs', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Example of 3NF but not BCNF:', 'R(A,B,C) with FDs: AB → C, C → B', 'R(A,B) with A → B', 'R(A,B,C) with A → B, B → C', 'R(A,B) with no FDs', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation is in BCNF if:', 'For every non-trivial FD X → Y, X is a superkey', 'For every FD, Y is part of key', 'No FDs exist', 'All attributes are keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'BCNF is stronger than 3NF because:', 'Every determinant must be a superkey', 'No transitive dependencies', 'No partial dependencies', 'All attributes atomic', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation in 3NF may not be in BCNF if:', 'There are overlapping candidate keys with FDs', 'There is a single candidate key', 'All attributes are prime', 'No FDs exist', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Given R(A,B,C) with FDs: AB → C, C → B. Candidate keys are:', 'AB and AC', 'AB only', 'AC only', 'BC', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'In this relation, C → B violates BCNF because:', 'C is not a superkey', 'C is a superkey', 'B is part of key', 'No violation', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'To convert to BCNF, we decompose into:', 'R1(C,B), R2(A,C)', 'R1(A,B,C), R2(C,B)', 'R1(A,B), R2(C,B)', 'R1(A,C), R2(A,B)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'BCNF decomposition is:', 'Lossless but may not preserve all FDs', 'Always preserves all FDs', 'May be lossy', 'Cannot be done', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Lossless join decomposition means:', 'Natural join of decomposed relations yields original without spurious tuples', 'No data is lost', 'All FDs preserved', 'No redundancy', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Dependency preservation means:', 'All FDs can be checked on individual relations', 'All data preserved', 'All keys preserved', 'No constraints needed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The chase algorithm is used to test:', 'Lossless join property', 'Dependency preservation', 'Normal form', 'Key status', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Fourth Normal Form (4NF) deals with:', 'Multivalued dependencies', 'Functional dependencies', 'Join dependencies', 'Transitive dependencies', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A multivalued dependency (MVD) X →→ Y means:', 'Y values are independent of other attributes', 'X determines Y uniquely', 'Y determines X', 'X and Y are related', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'MVD occurs when:', 'Two independent multi-valued facts exist in same relation', 'There is a functional dependency', 'There is a transitive dependency', 'There is a partial dependency', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Example of MVD: Person has multiple degrees and multiple languages:', 'Person →→ Degree, Person →→ Language', 'Person → Degree', 'Person → Language', 'Degree → Person', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation in 4NF must be in BCNF and have:', 'No non-trivial MVDs except FDs', 'No MVDs at all', 'No FDs', 'Only trivial MVDs', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Fifth Normal Form (5NF) deals with:', 'Join dependencies', 'Multivalued dependencies', 'Functional dependencies', 'Transitive dependencies', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A join dependency (JD) means:', 'Relation can be reconstructed from its projections', 'Relation can be joined', 'Relation has joins', 'Relation has dependencies', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A relation in 5NF has:', 'No non-trivial join dependencies', 'No FDs', 'No MVDs', 'All attributes as key', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Domain-Key Normal Form (DKNF) is:', 'Ultimate normal form with no modification anomalies', 'Same as 5NF', 'Same as BCNF', 'Same as 3NF', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Lossless join decomposition ensures:', 'No information is lost when joining back', 'All FDs preserved', 'No redundancy', 'All keys preserved', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The condition for lossless join decomposition of R into R1 and R2 is:', 'R1 ∩ R2 → R1 or R1 ∩ R2 → R2', 'R1 ∩ R2 = ∅', 'R1 ∪ R2 = R', 'R1 = R2', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Dependency preserving decomposition allows:', 'Each FD checked on individual relations', 'FDs checked only after join', 'No FD checking', 'Only key constraints', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The projection of FDs on a decomposed relation includes:', 'FDs that involve only attributes of that relation', 'All original FDs', 'No FDs', 'Only key FDs', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A decomposition may be lossless but not:', 'Dependency preserving', 'Useful', 'Possible', 'Normalized', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Example of lossless but not dependency preserving:', 'BCNF decomposition of R(A,B,C) with AB → C, C → B', '3NF decomposition', '2NF decomposition', '1NF decomposition', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Denormalization is:', 'Introducing redundancy for performance', 'Further normalization', 'Removing all redundancy', 'Creating indexes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Denormalization is used to:', 'Improve query performance at cost of redundancy', 'Improve data integrity', 'Reduce storage', 'Eliminate anomalies', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Examples of denormalization include:', 'Pre-joining tables, storing derived columns', 'Splitting tables', 'Creating more tables', 'Adding foreign keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Denormalization risks:', 'Update anomalies, data inconsistency', 'Slower queries', 'Better integrity', 'Less storage', NULL, true),
