  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Deletion anomaly occurs when:', 'Deleting data removes unintended information', 'Cannot delete data', 'Delete is slow', 'Delete fails', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Example of deletion anomaly:', 'Deleting last employee removes department info', 'Deleting employee with ID', 'Deleting duplicate', 'Deleting NULL', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Update anomaly occurs when:', 'Updating data requires multiple changes due to redundancy', 'Cannot update', 'Update is slow', 'Update fails', NULL, true),
