  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Surrogate keys are:', 'Artificially generated unique identifiers', 'Natural keys from data', 'Composite keys', 'Foreign keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Advantages of surrogate keys:', 'Stable, simple, independent of business changes', 'Meaningful', 'Based on real data', 'Always composite', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Natural keys are:', 'Keys that exist in real-world data', 'Generated by system', 'Always single attribute', 'Always numeric', NULL, true),
