  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Associative entities are used for:', 'Many-to-many relationships', 'One-to-many relationships', 'One-to-one relationships', 'Recursive relationships', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Generalization in database design:', 'Subtype-supertype relationships', 'Specialization only', 'Aggregation', 'Composition', NULL, true),
