  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Aggregation represents:', 'Has-a relationship', 'Is-a relationship', 'Uses-a relationship', 'Creates-a relationship', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Composition is:', 'Strong form of aggregation with ownership', 'Weak aggregation', 'Generalization', 'Specialization', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The 3NF synthesis algorithm:', 'Produces dependency-preserving 3NF decomposition', 'Produces BCNF decomposition', 'Always lossless', 'Always dependency preserving', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The BCNF decomposition algorithm:', 'May not preserve all FDs', 'Always preserves FDs', 'Always produces 3NF', 'Cannot be applied', NULL, true),
