  ('ef9d65f3-726a-488a-af86-4074b784d357', 'DeptID and DeptID → DeptName. This is in:', '2NF (since single attribute key, no partial, but transitive DeptID → DeptName)', '3NF', 'BCNF', '1NF only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'After normalizing above to 3NF:', 'R1(SSN, Name, Address, DeptID), R2(DeptID, DeptName)', 'R1(SSN, Name, Address), R2(DeptID, DeptName)', 'R1(SSN, DeptID), R2(DeptID, DeptName)', 'R1(SSN, Name, Address, DeptName)', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Consider R(A,B,C,D) with FDs: AB → C, C → D, D → A. Candidate keys are:', 'AB, DB, CB', 'A only', 'B only', 'AB only', NULL, true),
