  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A transaction goes from active state to failed state when:', 'Normal execution cannot continue due to error', 'Transaction completes successfully', 'Transaction is rolled back', 'Transaction is aborted', NULL, true),
