  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Primary index equality on non-key retrieves:', 'Multiple records (selection cardinality s)', 'Single record always', 'No records', 'All records', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Cost with primary index and equality on non-key:', 'Height + s block accesses (if clustered, records in ≈ s/f_r blocks)', 'Height + b_r', 'b_r only', 's only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Secondary index equality on key (unique):', 'Height + 1 (index lookup + data access)', 'Height only', 'b_r', '1', NULL, true),
