  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Index scan for range condition (e.g., A > value):', 'Use index to find first match, then scan leaves/data', 'Full table scan only', 'No index use', 'Hash lookup', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Complex selections (AND/OR) can use:', 'Index intersection, index union, or bitmaps', 'Only sequential scan', 'Only single index', 'No optimization', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Conjunctive selection (σθ1∧θ2∧...∧θn) can use:', 'Most selective index first, then filter', 'Random index', 'No index', 'All indexes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'External sorting is used when:', 'Data doesn''t fit in main memory', 'Data fits in memory', 'No sorting needed', 'Data is small', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'External sort-merge algorithm uses:', 'Run generation phase and merge phase', 'Only one phase', 'Quick sort in memory', 'Bubble sort', NULL, true),
