  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Number of passes in merge phase =:', '⌈log_{M-1}(N/M)⌉ where M = buffer pages, N = runs', 'N × M', 'N / M', 'M^N', NULL, true),
