  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Nested-loop join (r ⋈ s) cost:', 'n_r × b_s + b_r (for block nested loop)', 'n_r × n_s', 'b_r + b_s', 'b_r × b_s', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Block nested-loop join uses:', 'One block of outer, compare with all blocks of inner', 'One tuple of outer, compare with all of inner', 'No blocks', 'Only indexes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Block nested-loop cost with buffer of M blocks:', 'b_r + ⌈b_r/(M-1)⌉ × b_s', 'b_r × b_s', 'b_r + b_s', 'n_r × n_s', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Indexed nested-loop join uses:', 'Index on inner relation for each outer tuple', 'No index', 'Full scan always', 'Hash join', NULL, true),
