  ('ef9d65f3-726a-488a-af86-4074b784d357', 'When privileges are revoked, they should be treated as if:', 'They had never been granted (proper propagation)', 'They still exist for backward compatibility', 'Only the first user loses access', 'They remain until session ends', NULL, true),
