  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Roles can be password-protected to:', 'Prevent unauthorized enabling of the role', 'Encrypt role data', 'Hide role name', 'Delete the role', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Secure application roles are:', 'Roles implemented by a package that validates conditions before enabling', 'Roles with no privileges', 'Public roles', 'Default roles', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Enterprise roles in Oracle:', 'Contain global roles on multiple databases and are granted to enterprise users', 'Are local to one database only', 'Cannot be granted to users', 'Have no privileges', NULL, true),
