  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Discretionary Access Control (DAC) allows:', 'Object owners to grant access to others at their discretion', 'System-wide mandatory rules', 'Role-based assignments only', 'No user control', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Mandatory Access Control (MAC) uses:', 'Labels and clearances to enforce system-wide security policy', 'User discretion for access', 'Only roles for access', 'No labels', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Role-Based Access Control (RBAC) assigns:', 'Permissions to roles, and roles to users based on job functions', 'Permissions directly to users', 'No roles', 'Only system privileges', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The principle of least privilege means:', 'Users get only the minimum permissions needed to perform their job', 'Users get all possible permissions', 'Users get no permissions', 'Permissions are unlimited', NULL, true),
