  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Row-level security restricts access to:', 'Specific rows based on user attributes or policies', 'Entire tables only', 'Only columns', 'No data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Column-level security restricts access to:', 'Specific columns within tables', 'Entire tables only', 'Only rows', 'No data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Virtual Private Database (VPD) provides:', 'Fine-grained access control by dynamically adding predicates to queries', 'No access control', 'Only table-level security', 'Only network security', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Encryption is:', 'Transforming data into unreadable format using algorithm and key', 'Making data readable', 'Deleting data', 'Backing up data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Decryption is:', 'Converting encrypted data back to original form using key', 'Encrypting data', 'Hashing data', 'Compressing data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Transparent Data Encryption (TDE) automatically:', 'Encrypts data written to disk and decrypts when read, without application changes', 'Requires application modification', 'Only works for backups', 'Only encrypts network traffic', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'TDE protects data:', 'At rest (on disk)', 'In transit', 'In memory', 'Only during backups', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Network encryption (SSL/TLS) protects data:', 'In transit between client and server', 'At rest on disk', 'In CPU registers', 'Only during authentication', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Encryption algorithms include:', 'AES (Advanced Encryption Standard), DES, 3DES', 'MD5, SHA (these are hash functions)', 'SQL, PL/SQL', 'HTML, XML', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Symmetric encryption uses:', 'Same key for encryption and decryption', 'Different keys for encryption and decryption', 'No keys', 'Public keys only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Asymmetric encryption uses:', 'Public key for encryption, private key for decryption', 'Same key for both', 'No keys', 'Only passwords', NULL, true),
