  ('ef9d65f3-726a-488a-af86-4074b784d357', 'PCI-DSS compliance often requires:', 'Encryption of cardholder data', 'No encryption', 'Public data only', 'Backup only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'HIPAA security rule requires protection of:', 'Electronic protected health information (ePHI)', 'Only financial data', 'Only public data', 'No specific data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Data masking (redaction) is:', 'Hiding sensitive data by displaying modified values', 'Encrypting all data', 'Deleting sensitive data', 'Backing up data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Dynamic data masking:', 'Masks data in query results in real-time without changing underlying data', 'Permanently changes data', 'Encrypts data on disk', 'Only works for backups', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Full data redaction displays:', 'Completely redacted values (e.g., all columns show spaces or zeros)', 'Original data', 'Encrypted data', 'No data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Partial data redaction displays:', 'Only portions of data (e.g., credit card shows last 4 digits)', 'Complete data', 'No data', 'Encrypted data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Random data redaction displays:', 'Randomly generated values for each query', 'Consistent masked values', 'Original values', 'No values', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Database auditing is:', 'Tracking and logging database activities for security analysis', 'Encrypting data', 'Creating users', 'Backing up data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Audit records typically capture:', 'User, operation, timestamp, object accessed, success/failure', 'Only username', 'Only timestamp', 'No information', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'An intrusion detection system (IDS):', 'Monitors for suspicious activity and alerts administrators', 'Prevents all intrusions', 'Encrypts all data', 'Manages users', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'SIEM (Security Information and Event Management) systems:', 'Collect and analyze logs from multiple sources for real-time monitoring', 'Only store logs', 'Only encrypt data', 'Only manage users', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Failed login attempts should be audited to detect:', 'Brute force attacks', 'Successful logins', 'Normal activity', 'Scheduled maintenance', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Privilege usage auditing helps identify:', 'Unnecessary privileges that can be revoked', 'All users', 'All tables', 'All indexes', NULL, true),
