  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Parameterized queries (prepared statements) prevent SQL injection by:', 'Separating SQL code from user input', 'Concatenating user input with SQL', 'Disabling all input', 'Using dynamic SQL only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Stored procedures can help prevent SQL injection by:', 'Encapsulating SQL logic and validating input', 'Allowing direct table access', 'Using dynamic SQL only', 'Disabling all security', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Input validation involves:', 'Checking user input for malicious content before processing', 'Accepting all input without checking', 'Disabling all input', 'Encrypting input only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Least privilege for application accounts means:', 'Application connects with minimal needed privileges, not DBA', 'Application uses sa or root account', 'Application has no privileges', 'Application uses public role only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Inference attacks occur when:', 'Legitimate data is used to deduce unknown sensitive information', 'Data is directly accessed without authorization', 'Passwords are stolen', 'Encryption is broken', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Cell suppression protects against inference by:', 'Removing or leaving blank some cells in published data', 'Encrypting all cells', 'Duplicating cells', 'Adding more data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Generalization protects against inference by:', 'Replacing specific values with broader categories (e.g., age 25 → 20-30)', 'Showing exact values', 'Encrypting values', 'Deleting values', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Noise addition protects against inference by:', 'Adding random values to data to obscure exact values', 'Removing all data', 'Encrypting data', 'Duplicating data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'k-anonymity requires that:', 'Each record is indistinguishable from at least k-1 others on quasi-identifiers', 'All records are unique', 'All data is encrypted', 'No data is released', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Backup security requires:', 'Encrypting backups and securing backup storage', 'Leaving backups unsecured for quick recovery', 'Only storing backups locally', 'Never testing backups', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Backup encryption protects against:', 'Theft of backup media', 'Only online attacks', 'Only network attacks', 'Only user errors', NULL, true),
