  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Database hardening involves:', 'Removing unnecessary services, securing configuration, applying patches', 'Adding more services', 'Opening all ports', 'Disabling all security', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Patch management is important because:', 'Unpatched vulnerabilities are common attack vectors', 'Patches slow down database', 'Patches are optional', 'Patches never fix security issues', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The Common Vulnerability Scoring System (CVSS) provides:', 'Standardized severity scores for vulnerabilities', 'Patch installation instructions', 'Encryption algorithms', 'User management tools', NULL, true),
