  ('ef9d65f3-726a-488a-af86-4074b784d357', 'SOX (Sarbanes-Oxley) requires:', 'Controls over financial reporting data', 'Only IT general controls', 'No data protection', 'Only physical security', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'PCI-DSS applies to:', 'Organizations handling payment card data', 'All businesses', 'Only banks', 'Only government agencies', NULL, true),
