  ('ef9d65f3-726a-488a-af86-4074b784d357', 'connected by a network', 'Multiple copies of the same database at one site', 'A single database on one server', 'A backup database at remote location', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'users', 'Multiple DBMSs running independently', 'A single centralized DBMS', 'A file sharing system', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The main reasons for adopting distributed databases include:', 'Reliability, scalability, local autonomy, cost-effectiveness', 'Only better security', 'Only faster queries', 'Only easier management', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Local autonomy in distributed databases means:', 'Each site has control over its own local data and processing', 'All sites controlled by central site', 'No local control', 'Only remote access allowed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Transparency in distributed databases refers to:', 'Hiding details of distribution from users and applications', 'Making distribution visible to users', 'No network connectivity', 'Only local access', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The two main types of distributed database systems are:', 'Homogeneous and Heterogeneous', 'Centralized and Decentralized', 'Client-Server and Peer-to-Peer', 'Local and Remote', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Homogeneous distributed databases have:', 'Same DBMS software at all sites', 'Different DBMS software at different sites', 'No DBMS software', 'Only one site', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Heterogeneous distributed databases have:', 'Different DBMS software, possibly different data models', 'Same DBMS software everywhere', 'No network connectivity', 'Only one DBMS type', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Federated database system is a type of:', 'Heterogeneous distributed database with local autonomy', 'Homogeneous database', 'Centralized database', 'Single-user database', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Client-server architecture in distributed databases has:', 'Clients request services, servers provide them', 'All nodes are equal', 'No distinction between client and server', 'Only servers exist', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Peer-to-peer distributed database has:', 'All nodes have equal capabilities and cooperate', 'Central coordinator node', 'Only client nodes', 'Only server nodes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Multi-database system (MDBS) is:', 'System that integrates multiple autonomous, possibly heterogeneous databases', 'Single database with multiple tables', 'Multiple copies of same database', 'Backup system', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Data fragmentation divides:', 'A relation into smaller pieces (fragments) stored at different sites', 'The database into tables', 'The index into parts', 'The transaction into subtransactions', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The main types of fragmentation are:', 'Horizontal, Vertical, and Mixed (Hybrid)', 'Primary and Secondary', 'Dense and Sparse', 'Clustered and Non-clustered', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Horizontal fragmentation divides:', 'A relation by rows (tuples) into subsets of rows', 'A relation by columns', 'A relation by both rows and columns', 'The index structure', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Horizontal fragmentation is typically based on:', 'Predicates (conditions) on attributes', 'Random assignment', 'Row size', 'Row creation time', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Example of horizontal fragmentation:', 'Employees in different regions stored at respective regional sites', 'Employees table split by columns (name at one site, salary at another)', 'Employees table with all rows at all sites', 'Employees table with no fragmentation', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Vertical fragmentation divides:', 'A relation by columns (attributes) into subsets of columns', 'A relation by rows', 'The entire database', 'The index only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Vertical fragmentation requires:', 'A common attribute (usually primary key) in each fragment for reconstruction', 'No common attributes', 'All columns in every fragment', 'Random column assignment', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Mixed (hybrid) fragmentation applies:', 'Both horizontal and vertical fragmentation', 'Only one type', 'No fragmentation', 'Only replication', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Correctness rules for fragmentation include:', 'Completeness, Reconstruction, Disjointness', 'Atomicity, Consistency, Isolation', 'Selectivity, Cardinality, Degree', 'Redundancy, Replication, Distribution', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Completeness rule ensures:', 'Every data item appears in at least one fragment', 'Data appears in multiple fragments', 'Data appears in no fragments', 'Only some data appears', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Reconstruction rule ensures:', 'Original relation can be reconstructed from fragments', 'Fragments cannot be combined', 'Data is lost after fragmentation', 'No reconstruction possible', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Disjointness rule ensures (for horizontal fragmentation):', 'Fragments are disjoint (no overlapping rows)', 'Fragments overlap', 'All rows in all fragments', 'No rows in fragments', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'For vertical fragmentation, disjointness applies to:', 'Non-primary key attributes (overlap only on primary key)', 'All attributes including primary key', 'No attributes', 'Only foreign keys', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Data replication means:', 'Storing copies of data fragments at multiple sites', 'Storing data only once', 'Fragmenting data', 'Indexing data', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The main types of replication are:', 'Full replication and Partial replication', 'Horizontal and Vertical replication', 'Synchronous and Asynchronous (main distinction)', 'Primary and Secondary replication', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Full replication means:', 'Entire database is copied to all sites', 'Only parts of database are copied', 'No copies exist', 'Only indexes are copied', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Partial replication means:', 'Some fragments are replicated, others not', 'All fragments replicated everywhere', 'No replication', 'Only one copy exists', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Advantages of replication include:', 'Increased availability, improved read performance, fault tolerance', 'Slower reads, lower availability', 'Increased complexity only', 'No advantages', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Disadvantages of replication include:', 'Update overhead, consistency maintenance, storage cost', 'Faster updates', 'Lower storage cost', 'Simpler management', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Synchronous replication ensures:', 'All copies are updated within the same transaction (immediate consistency)', 'Updates propagate later', 'No updates', 'Only reads allowed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Asynchronous replication:', 'Updates propagate after transaction commits (eventual consistency)', 'Updates happen simultaneously', 'No updates allowed', 'Only synchronous allowed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Master-slave replication has:', 'One primary (master) for writes, multiple slaves for reads', 'All nodes can write', 'No writes allowed', 'Only reads allowed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Multi-master replication allows:', 'Writes at any node, with conflict resolution', 'Only one node for writes', 'No writes', 'Only reads', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Distribution transparency types include:', 'Fragmentation transparency, Location transparency, Replication transparency', 'Only location transparency', 'Only fragmentation transparency', 'No transparency', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Fragmentation transparency means:', 'User unaware that data is fragmented, queries as if whole relation exists', 'User must specify fragments', 'Fragments are visible to users', 'No fragmentation exists', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Location transparency means:', 'User unaware of where data is physically stored', 'User must specify site addresses', 'Locations are visible', 'No location information', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Replication transparency means:', 'User unaware that data is replicated', 'User must manage copies', 'Replication visible to users', 'No replication exists', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Local mapping transparency means:', 'User must know both fragment and location names (lowest level)', 'No transparency', 'Complete transparency', 'Only fragment names needed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Distributed query processing involves:', 'Query decomposition, data localization, global optimization, local optimization', 'Only local processing', 'Only network transfer', 'No optimization', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Query decomposition (first phase) is similar to centralized:', 'Parse, validate, rewrite into relational algebra', 'Data localization', 'Site selection', 'Execution', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Data localization determines:', 'Which fragments contain required data and how to access them', 'Which sites to use', 'Join order', 'Index selection', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'processing costs', 'Only local optimization', 'Random strategy', 'No optimization', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'tuples', 'All data always transferred', 'Local processing only', 'No reduction', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Semi-join operation:', 'R ⋉ S = π_R(R ⋈ S) - sends join attributes of S to R site', 'R ⋈ S (full join)', 'R × S', 'R ∪ S', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Join strategies in distributed databases include:', 'Ship whole relation, fetch-as-needed, semi-join based, partitioned join', 'Only nested loop', 'Only sort-merge', 'Only hash join', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Ship whole relation strategy:', 'Transfer entire smaller relation to larger relation''s site and join locally', 'Transfer both relations to third site', 'Transfer no data', 'Join at both sites', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'index', 'Transfer all data first', 'No data transfer', 'Join at both sites', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Cost of distributed query includes:', 'I/O cost + CPU cost + Communication cost', 'Only communication cost', 'Only I/O cost', 'Only CPU cost', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'A distributed transaction is:', 'Transaction that accesses data at multiple sites', 'Transaction at single site only', 'Read-only transaction', 'Update transaction only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Distributed transaction has:', 'One coordinator and multiple participants (subtransactions)', 'Only one participant', 'No coordinator', 'Only local processing', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Two-Phase Commit (2PC) protocol ensures:', 'Atomic commitment of distributed transactions across sites', 'No commit coordination', 'Local commits only', 'Partial commits', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The two phases of 2PC are:', 'Prepare phase and Commit/Abort phase', 'Lock phase and Unlock phase', 'Read phase and Write phase', 'Start phase and End phase', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'In prepare phase, coordinator:', 'Sends "prepare" message to all participants, waits for votes (YES/NO)', 'Commits immediately', 'Aborts all', 'Does nothing', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'In commit phase, if all participants vote YES:', 'Coordinator sends "commit" message, participants commit', 'Coordinator aborts', 'Participants decide independently', 'Transaction continues', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'If any participant votes NO in prepare phase:', 'Coordinator sends "abort" message, all participants abort', 'Commit anyway', 'Only that participant aborts', 'Retry', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Presumed Abort (PA) protocol:', 'If coordinator fails, assume abort unless commit record found', 'Assume commit always', 'No assumption', 'Always commit', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Presumed Commit (PC) protocol:', 'Assume commit unless abort record found', 'Assume abort always', 'No assumption', 'Always abort', NULL, true),
