  ('ef9d65f3-726a-488a-af86-4074b784d357', 'CAP theorem states:', 'Cannot have all three: Consistency, Availability, Partition tolerance simultaneously', 'Can have all three', 'Only two matter', 'Only one matters', NULL, true),
