  ('ef9d65f3-726a-488a-af86-4074b784d357', 'CA systems (Consistency + Availability) assume:', 'No network partitions (theoretical, not practical)', 'Partitions always occur', 'Partitions are handled', 'Consistency is sacrificed', NULL, true),
