  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Use cases for graph databases include:', 'Social networks, recommendation engines, fraud detection, knowledge graphs', 'Session storage', 'Caching', 'Logging', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'NewSQL databases aim to:', 'Provide ACID transactions and SQL with NoSQL scalability', 'Replace SQL completely', 'Only be in-memory', 'Only be distributed', NULL, true),
