  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Time-series databases optimize for:', 'Data with timestamps (metrics, events, sensor data)', 'Relational data', 'Graph data', 'Key-value pairs', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Examples of time-series databases include:', 'InfluxDB, Prometheus, TimescaleDB, OpenTSDB', 'MongoDB, CouchDB', 'Neo4j, JanusGraph', 'Redis, Memcached', NULL, true),
