  ('ef9d65f3-726a-488a-af86-4074b784d357', 'When to choose Document stores:', 'Semi-structured data, evolving schema, hierarchical data', 'Highly relational data', 'Simple key lookups only', 'Graph traversals', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'When to choose Key-Value stores:', 'Simple lookups by key, high throughput, caching', 'Complex queries', 'Joins', 'Relationship queries', NULL, true),
