  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Cloud-native databases are:', 'Designed for cloud environments (elastic, managed, serverless)', 'On-premise only', 'Not scalable', 'Only relational', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Serverless databases:', 'Automatically scale, pay-per-use, no server management', 'Require server provisioning', 'Fixed capacity', 'Only on-premise', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Multi-model databases support:', 'Multiple data models (document, graph, relational) in one system', 'Only one model', 'No models', 'Only key-value', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Examples of multi-model databases:', 'ArangoDB, OrientDB, Cosmos DB', 'MongoDB only', 'Cassandra only', 'Neo4j only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Database as a Service (DBaaS) provides:', 'Managed database in cloud (setup, backups, scaling handled)', 'On-premise only', 'User manages everything', 'No automation', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Hybrid transaction/analytical processing (HTAP) databases:', 'Handle both OLTP and OLAP workloads', 'Only OLTP', 'Only OLAP', 'Neither', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'support decision making', 'A backup copy of operational databases', 'A large relational database for OLTP', 'A collection of files on a file server', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The four key characteristics of a data warehouse are:', 'Subject-oriented, Integrated, Time-variant, Non-volatile', 'Distributed, Parallel, Scalable, Available', 'Atomic, Consistent, Isolated, Durable', 'Fast, Reliable, Secure, Accessible', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'applications', 'Data organized by database subjects', 'Data organized by user preferences', 'Data organized by transaction types', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'conventions', 'Data is stored in one integrated database', 'Data is integrated with applications', 'Data is integrated with the operating system', NULL, NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', '"Time-variant" in data warehouse means:', 'Data contains historical information with time stamps', 'Data changes frequently over time', 'Data is only current', 'Data expires after time', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', '"Non-volatile" in data warehouse means:', 'Data is read-only and not updated by users', 'Data changes frequently', 'Data is volatile in memory', 'Data disappears after use', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The primary purpose of a data warehouse is to support:', 'Decision support and business intelligence', 'Online transaction processing', 'Day-to-day operations', 'Data entry', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Data warehouse vs Database (OLTP): Data warehouse is optimized for:', 'Complex queries and analysis', 'Frequent updates and inserts', 'Small transactions', 'Real-time processing', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'OLTP stands for:', 'Online Transaction Processing', 'Online Table Processing', 'Offline Transaction Processing', 'Online Transfer Protocol', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'OLAP stands for:', 'Online Analytical Processing', 'Online Application Processing', 'Offline Analytical Processing', 'Online Analysis Protocol', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'OLAP systems are characterized by:', 'Read-mostly operations, complex queries, historical data', 'Frequent writes, simple queries, current data', 'No queries, only updates', 'Only insert operations', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'OLTP systems are characterized by:', 'Short, atomic transactions with frequent updates', 'Long-running complex queries', 'Read-only operations', 'Batch processing only', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Which of the following is NOT an OLAP operation?', 'INSERT', 'Roll-up', 'Drill-down', 'Slice and dice', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Roll-up operation in OLAP:', 'Aggregates data by moving up in concept hierarchy (e.g., city → country)', 'Drills down to detail data', 'Selects a subset of dimensions', 'Rotates the cube view', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Drill-down operation in OLAP:', 'Navigates from summary to more detailed data', 'Aggregates to higher level', 'Removes dimensions', 'Adds dimensions', NULL, true),
