  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Data mart is appropriate when:', 'A department needs focused, summarized data without building full warehouse', 'Enterprise-wide integration is required', 'All data must be centralized', 'No analysis is needed', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'making', 'Historical data repository', 'Backup storage', 'Data warehouse subset', NULL, NULL, true),
