  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Top tier of data warehouse architecture includes:', 'Query and reporting tools, analysis tools, data mining tools', 'Data sources', 'Database server', 'ETL processes', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'Staging area in data warehouse architecture:', 'Temporary storage for data cleaning and transformation before loading', 'Final storage area', 'User query area', 'Backup area', NULL, true),
  ('ef9d65f3-726a-488a-af86-4074b784d357', 'The three data warehouse models from architecture perspective are:', 'Virtual warehouse, Data mart, Enterprise warehouse', 'Star, Snowflake, Fact constellation', 'Relational, Multidimensional, Hybrid', 'Centralized, Distributed, Federated', NULL, true),
