INSERT INTO questions (subject_id, question_text, option_a, option_b, option_c, option_d, option_e, is_active) VALUES
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is a characteristic of Artificial Intelligence?', 'It mimics human cognitive functions such as learning and problem-solving', 'It can only perform tasks it is explicitly programmed to do', 'It requires no data to function', 'It is limited to rule-based systems', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'What is the main goal of Machine Learning?', 'To enable computers to learn from data without being explicitly programmed', 'To program computers to follow explicit instructions', 'To replace human intelligence entirely', 'To create expert systems based on rules', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is an example of supervised learning?', 'Predicting house prices based on historical data', 'Grouping customers into segments based on purchasing behavior', 'Finding patterns in unlabeled data', 'Playing a game by learning from rewards', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'In unsupervised learning, the algorithm:', 'Finds hidden patterns or intrinsic structures in unlabeled data', 'Learns from labeled data to make predictions', 'Learns through trial and error with rewards', 'Uses a teacher to correct mistakes', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Reinforcement learning is characterized by:', 'Learning from interactions with an environment to maximize cumulative reward', 'Learning from labeled examples', 'Learning from unlabeled data', 'Learning from a fixed dataset', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Data analytics primarily involves:', 'Using statistical and computational techniques to extract insights from data', 'Collecting data without any analysis', 'Designing neural networks', 'Writing code for data storage', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is a type of AI that can perform any intellectual task that a human can?', 'General AI', 'Narrow AI', 'Super AI', 'Weak AI', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'The Turing Test is used to assess:', 'A machine''s ability to exhibit intelligent behavior equivalent to a human', 'A machine''s processing speed', 'A machine''s memory capacity', 'A machine''s ability to learn', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is an application of machine learning?', 'Recommendation systems', 'Spell checker', 'Compiler design', 'Operating system', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'The term "Big Data" is characterized by:', 'Large volume, high velocity, and wide variety', 'Only large volume', 'Only structured data', 'Data that cannot be processed', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'What is the difference between AI and Machine Learning?', 'Machine Learning is a subset of AI', 'AI is a subset of Machine Learning', 'They are the same', 'AI is about data, ML is about algorithms', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is not a type of machine learning?', 'Deterministic learning', 'Supervised learning', 'Unsupervised learning', 'Reinforcement learning', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'In data analytics, what is the purpose of descriptive analytics?', 'To describe what has happened in the past', 'To predict future outcomes', 'To prescribe actions', 'To diagnose causes', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Predictive analytics uses techniques such as:', 'Regression and classification', 'Clustering', 'Association rules', 'Data visualization', NULL, true),
