  ('846bb4e7-894e-4946-9074-e7534ddae770', 'The concept of "weak AI" refers to:', 'AI designed to perform a specific task', 'AI that is not very intelligent', 'AI that can perform any intellectual task', 'AI that is not yet developed', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is an example of a rule-based system?', 'Expert system', 'Neural network', 'Decision tree', 'Support vector machine', NULL, true),
