  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is a common application of AI in healthcare?', 'All of the above', 'Medical image analysis', 'Drug discovery', 'Personalized treatment', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'The concept of "overfitting" in machine learning means:', 'The model performs well on training data but poorly on unseen data', 'The model performs poorly on training data', 'The model is too simple', 'The model has high bias', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is a type of AI that learns from experience?', 'Machine learning system', 'Rule-based system', 'Expert system', 'Symbolic AI', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'What is the dot product of two vectors [1,2,3] and [4,5,6]?', '32', '40', '23', '30', NULL, true),
