  ('846bb4e7-894e-4946-9074-e7534ddae770', 'The derivative of the function f(x) = x^3 + 2x^2 - 5x + 3 is:', '3x^2 + 4x - 5', '3x^2 + 4x + 5', '3x^2 + 2x - 5', '3x^2 + 4x - 3', NULL, true),
