  ('846bb4e7-894e-4946-9074-e7534ddae770', 'The derivative of the sigmoid function σ(x) = 1/(1+e^{-x}) is:', 'Both A and C are equivalent', 'σ(x)(1-σ(x))', 'σ(x) (1+σ(x))', 'e^{-x}/(1+e^{-x})^2', NULL, true),
  ('846bb4e7-894e-4946-9074-e7534ddae770', 'Which of the following is a measure of central tendency?', 'Median', 'Variance', 'Standard deviation', 'Range', NULL, true),
