  ('846bb4e7-894e-4946-9074-e7534ddae770', 'In calculus, a function has a local minimum at x0 if:', 'f''(x0)=0 and f''''(x0)>0', 'f''(x0)=0 and f''''(x0)<0', 'f''(x0)>0', 'f''(x0)<0', NULL, true),
