INSERT INTO questions (subject_id, question_text, option_a, option_b, option_c, option_d, option_e, is_active) VALUES
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'What is a problem in the context of problem-solving?', 'A gap between current state and desired state', 'A situation that requires no action', 'A random event', 'A solved equation', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is the first step in the problem-solving process?', 'Understanding the problem', 'Implementing a solution', 'Evaluating the solution', 'Generating alternatives', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'A well-defined problem has:', 'Clear goals and constraints', 'Multiple interpretations', 'No specified initial state', 'Unlimited resources', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'An ill-defined problem is characterized by:', 'Vague goals and unclear constraints', 'A single correct answer', 'Well-specified initial conditions', 'Known solution path', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is an example of a well-defined problem?', '"Solve for x in 2x + 5 = 13"', '"Write a beautiful poem"', '"Design a better car"', '"Be happy"', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Problem-solving strategies include:', 'All of the above', 'Trial and error', 'Heuristics', 'Algorithms', NULL, true),
