  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'A heuristic is a:', 'Mental shortcut or rule of thumb', 'Guaranteed solution method', 'Type of algorithm', 'Mathematical formula', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is a heuristic?', 'All of the above', 'Working backwards', 'Means-ends analysis', 'Hill climbing', NULL, true),
