  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is a common obstacle in problem-solving?', 'All of the above', 'Functional fixedness', 'Mental set', 'Confirmation bias', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Functional fixedness is:', 'Inability to see an object''s unusual use', 'Tendency to repeat solutions', 'Focusing on confirming beliefs', 'None', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'A mental set is:', 'Tendency to approach problems in a certain way', 'A set of mental tools', 'A fixed mindset', 'None', NULL, true),
