  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Convergent thinking is:', 'Narrowing down to the best solution', 'Generating many ideas', 'Brainstorming', 'None', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is a creative problem-solving technique?', 'All of the above', 'Brainstorming', 'Mind mapping', 'SCAMPER', NULL, true),
