  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is a problem-solving approach in computer science?', 'All of the above', 'Divide and conquer', 'Dynamic programming', 'Greedy algorithms', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'The difference between an expert and a novice problem-solver is:', 'All of the above', 'Experts have more domain knowledge', 'Experts use better strategies', 'Experts recognize patterns faster', NULL, true),
  ('8cb3a76b-984d-429c-bcdc-701aac209302', 'Which of the following is a common problem-solving pitfall?', 'All of the above', 'Jumping to conclusions', 'Lack of planning', 'Ignoring constraints', NULL, true),
