  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which one of the following is not true?', 'An abstract class cannot have non-abstract methods.', 'A class containing abstract methods is called an abstract class.', 'Abstract methods should be implemented in the derived class.', 'A class must be qualified as ‘abstract’ class, if it contains one abstract method.', 'None of the above.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'The fields in an interface are implicitly specified as,', 'both static and final', 'static only', 'protected', 'private', 'none of the above.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which of the following is not true?', 'An interface can implement another interface.', 'An interface can extend another interface.', 'A class which is implementing an interface must implement all the methods of the interface.', 'An interface is a solution for multiple inheritance in java.', 'None of the above.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which of the following is true?', 'A finally block is executed whether an exception is thrown or not.', 'A finally block is executed before the catch block but after the try block.', 'A finally block is executed, only after the catch block is executed.', 'A finally block is executed, only if an exception occurs.', 'None of the above.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Among these expressions, which is(arE. of type String?', 'Both A. and B. above E. A., B. and C. above.', '“0”', '“ab” + “cd”', '‘0’', NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which of the following is TRUE?', 'A class has always a constructor (possibly automatically supplied by the java compiler).', 'In java, an instance field declared public generates a compilation error.', 'int is the name of a class available in the package java.lang', 'Instance variable names may only contain letters and digits.', 'The more comments in a program, the faster the program runs.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'A constructor', 'A., B. and C. above.', 'Must have the same name as the class it is declared within.', 'Is used to create objects.', 'May be declared private', 'Both A. and B. above', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'The correct order of the declarations in a Java program is,', 'Package declaration, import statement, class declaration', 'Import statement, package declaration, class declaration', 'Import statement, class declaration, package declaration', 'Class declaration, import statement, package declaration', 'Class declaration, package declaration, import statement.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'An overloaded method consists of,', 'Both A. and B. above', 'The same method name with different types of parameters', 'The same method name with different number of parameters', 'The same method name and same number and type of parameters with different return type', 'A., B. and C. above.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'All exception types are subclasses of the built-in class', 'Throwable', 'Exception', 'RuntimeException', 'Error', 'None of the above.', true),
