  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Members of a class specified as ……………….. are accessible only to methods of that class.', 'Private', 'Protected', 'Final', 'Public', 'Static.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Multiple inheritances is not supported in case of class but it is supported in case of interface.', 'True', 'False', NULL, NULL, NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', '……………….. are used to document a program and improve its readability.', 'Comments', 'System cells', 'Keywords', 'Control structures', 'Blocks.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'In Java, a try block should immediately be followed by one or more ……………….. blocks.', 'Catch', 'Throw', 'Run', 'Exit', 'Error.', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'An abstract data type typically comprises a …………… and a set of ……………… respectively.', 'Data representation, operations.', 'Data representation, classes', 'Database, operations', 'Data representation, objects', 'Control structure, operations', true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'In object-oriented programming, the process by which one object acquires the properties of another object is called', 'Inheritance', 'Encapsulation', 'Polymorphism', 'Overloading', 'Overriding.', true),
