  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'What is the process of defining a method in a subclass having same name & type signature as a method in its superclass?', 'Method overriding', 'Method overloading', 'Method hiding', 'None of the mentioned', NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which of these keywords can be used to prevent Method overriding?', 'final', 'static', 'constant', 'protected', NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'An abstract class has no use when it is extended by some other class.', 'True', 'False', NULL, NULL, NULL, true),
