  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'An interface is a blueprint of a class. It has static constants and abstract methods.', 'True', 'False', NULL, NULL, NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which field cannot be changed after the object has been constructed?', 'Final field', 'Static field', 'Non-static field', 'Naming field', NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Which allows you to define one interface and have multiple implementations?', 'Polymorphism', 'Encapsulation', 'Inheritance', 'None of the above', NULL, true),
  ('3c061ec0-14e7-4707-8b41-aaa185b2ab95', 'Exception Handling is a mechanism to handle runtime errors', 'True', 'False', NULL, NULL, NULL, true),
